import{_ as a,o,c as t,ag as r}from"./chunks/framework.BKDXG6j6.js";const h=JSON.parse('{"title":"Memory Management","description":"","frontmatter":{},"headers":[],"relativePath":"performance/memory.md","filePath":"performance/memory.md","lastUpdated":null}'),n={name:"performance/memory.md"};function i(s,e,l,c,d,m){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="memory-management" tabindex="-1">Memory Management <a class="header-anchor" href="#memory-management" aria-label="Permalink to &quot;Memory Management&quot;">​</a></h1><p>Android devices operate in heavily constrained memory environments. Poor memory management leads to high OutOfMemoryError (OOM) crashes, sluggish app performance, and the app being killed aggressively when in the background.</p><h2 id="understanding-garbage-collection-gc" tabindex="-1">Understanding Garbage Collection (GC) <a class="header-anchor" href="#understanding-garbage-collection-gc" aria-label="Permalink to &quot;Understanding Garbage Collection (GC)&quot;">​</a></h2><p>The Android Runtime (ART) features an advanced Garbage Collector. When an object is no longer referenced by a &quot;GC Root&quot; (like an active thread, local variable, or static variable), it becomes eligible for collection.</p><ul><li><strong>Minor GC:</strong> Frees small objects. Happens incredibly fast, concurrently.</li><li><strong>Major GC:</strong> Frees larger objects or old generation spaces. If an app allocates memory continuously, heavy GC pauses will drop UI frames (&quot;GC Churn&quot;).</li></ul><h2 id="causes-of-memory-leaks" tabindex="-1">Causes of Memory Leaks <a class="header-anchor" href="#causes-of-memory-leaks" aria-label="Permalink to &quot;Causes of Memory Leaks&quot;">​</a></h2><p>A memory leak occurs when an object is no longer needed but is still referenced by a GC Root, preventing garbage collection.</p><h3 id="_1-context-leaks" tabindex="-1">1. Context Leaks <a class="header-anchor" href="#_1-context-leaks" aria-label="Permalink to &quot;1. Context Leaks&quot;">​</a></h3><p>Passing an <code>Activity</code> context to a long-lived object (like a Singleton, ViewModel, or Coroutine).</p><ul><li><strong>Fix:</strong> If a Singleton or Repository needs a context for Room or SharedPreferences, <em>only</em> pass the Application Context (<code>context.applicationContext</code>).</li></ul><h3 id="_2-static-views" tabindex="-1">2. Static Views <a class="header-anchor" href="#_2-static-views" aria-label="Permalink to &quot;2. Static Views&quot;">​</a></h3><p>Never hold <code>View</code>, <code>Activity</code>, or <code>Fragment</code> references in <code>object</code> singletons or <code>companion objects</code>.</p><h3 id="_3-inner-classes-and-callbacks" tabindex="-1">3. Inner Classes and Callbacks <a class="header-anchor" href="#_3-inner-classes-and-callbacks" aria-label="Permalink to &quot;3. Inner Classes and Callbacks&quot;">​</a></h3><p>Anonymous inner classes (like traditional Java <code>Runnable</code> or <code>Retrofit Callback</code>) hold an implicit reference to their outer class.</p><ul><li><strong>Fix:</strong> Use static inner classes, or modern Kotlin standard Coroutines, which cancel securely using CoroutineScope.</li></ul><h3 id="_4-unregistered-listeners" tabindex="-1">4. Unregistered Listeners <a class="header-anchor" href="#_4-unregistered-listeners" aria-label="Permalink to &quot;4. Unregistered Listeners&quot;">​</a></h3><p>If you register a listener (e.g., <code>LocationManager</code>, <code>SensorManager</code>, <code>BroadcastReceiver</code>) in <code>onCreate()</code> or <code>onStart()</code>, you <em>must</em> unregister it in the symmetrical teardown method (<code>onDestroy()</code> or <code>onStop()</code>).</p><h2 id="detecting-memory-leaks" tabindex="-1">Detecting Memory Leaks <a class="header-anchor" href="#detecting-memory-leaks" aria-label="Permalink to &quot;Detecting Memory Leaks&quot;">​</a></h2><h3 id="leakcanary" tabindex="-1">LeakCanary <a class="header-anchor" href="#leakcanary" aria-label="Permalink to &quot;LeakCanary&quot;">​</a></h3><p>The gold standard tool developed by Square. Add it as a <code>debugImplementation</code>. It automatically tracks Activity/Fragment destruction. If an Activity isn&#39;t GC&#39;d after standard teardown time, LeakCanary forcefully dumps the heap and extracts the shortest reference path causing the leak.</p><h3 id="android-studio-profiler" tabindex="-1">Android Studio Profiler <a class="header-anchor" href="#android-studio-profiler" aria-label="Permalink to &quot;Android Studio Profiler&quot;">​</a></h3><p>Capturing a Heap Dump (.hprof) allows deep visual inspection of memory. Look for Activity instances that exist in memory but have already passed their <code>onDestroy()</code> lifecycle.</p><h2 id="bitmaps" tabindex="-1">Bitmaps <a class="header-anchor" href="#bitmaps" aria-label="Permalink to &quot;Bitmaps&quot;">​</a></h2><p>Bitmaps are enormous. A single 12MP photo can consume 48MB of raw RAM if loaded uncompressed.</p><ul><li><strong>Glide or Coil:</strong> Always use an image loading library. They automatically downscale images to match the exact physical size of your ImageView and cache heavily.</li></ul><h2 id="interview-questions" tabindex="-1">Interview Questions <a class="header-anchor" href="#interview-questions" aria-label="Permalink to &quot;Interview Questions&quot;">​</a></h2><p><strong>Q: Explain why <code>LeakCanary</code> only runs in Debug builds.</strong><em>Answer:</em> <code>LeakCanary</code> intentionally induces Garbage Collection and performs Heap Dumps. A Heap Dump literally pauses the entire application thread for several seconds while it copies active memory to disk. This ruins the user experience and represents a massive security flaw, so it must rigorously be kept out of <code>release</code> builds.</p><p><strong>Q: How does a closure handle external references in a Coroutine?</strong><em>Answer:</em> A lambda sent into a coroutine captures its surrounding environment. If you reference <code>this</code> inside a View or Activity scope, the Coroutine holds the Activity alive. This is why you must explicitly tie coroutines to <code>viewModelScope</code> or <code>lifecycleScope</code> so they cancel automatically when the host dies, breaking the reference chain.</p>',28)])])}const p=a(n,[["render",i]]);export{h as __pageData,p as default};
